// Service for generating and storing backup codes
@Service
public class BackupCodeService {

    @Autowired
    private UserBackupCodeRepository repository;

    public String generateBackupCode(String username) {
        // Generate a random backup code
        String code = UUID.randomUUID().toString().substring(0, 6);

        // Save the backup code in the database
        UserBackupCode entity = new UserBackupCode();
        entity.setUsername(username);
        entity.setBackupCode(code);
        repository.save(entity);

        return code;
    }

    public boolean authenticateWithBackupCode(String username, String code) {
        // Find the backup code for the given user
        UserBackupCode entity = repository.findByUsername(username);

        // Check if the entered code matches the stored code
        return entity != null && entity.getBackupCode().equals(code);
    }
}

// Controller for handling MFA recovery requests
@RestController
public class RecoveryController {

    @Autowired
    private BackupCodeService service;

    @PostMapping("/recover")
    public String recoverAccount(@RequestBody RecoveryRequest request) {
        // Generate a backup code for the user
        String code = service.generateBackupCode(request.getUsername());

        // Return the backup code for the user
        return code;
    }

    @PostMapping("/authenticate")
    public boolean authenticateWithBackupCode(@RequestBody RecoveryRequest request) {
        // Authenticate the user with the provided backup code
        return service.authenticateWithBackupCode(request.getUsername(), request.getCode());
    }
}

